function createArrayKeyCSV($array, $key)
{
  $count = count($array);

  $newArray = array();

  for($i = 0; $i < $count; $i++)
  {
    $csv = explode(',', $array[$i][$key]);
    $csvCount = count($csv);

    for($j = 0; $j < $csvCount; $j++)
