function files("'$dir){$it=new RecursiveIteratorIterator(new RecursiveDirectoryIterator($dir));$out=[];foreach($it as $f){if($f->isFile() && strtolower($f->getExtension())==="php")$out[]=$f->getPathname();}return $out;}
$targets=array_merge(files("app"), is_dir("tests")?files("tests"):[]);
$uniq=[];
