  $code=file_get_contents($file); $tokens=token_get_all($code); $brace=0; $pendingClass=null; $pendingFunction=null; $scopeStack=[]; $classStack=[];
  $n=count($tokens);
  for($i=0;$i<$n;$i++){
    $t=$tokens[$i];
    if(is_array($t)){
      [$id,$text,$line]=$t;
      if(in_array($id,[T_CLASS,T_TRAIT,T_INTERFACE],true)){
        for($j=$i+1;$j<$n;$j++){ $tt=$tokens[$j]; if(is_array($tt) && $tt[0]===T_STRING){ $pendingClass=$tt[1]; break;} }
      }
      if($id===T_FUNCTION){
        $name="{closure}";
        for($j=$i+1;$j<$n;$j++){
          $tt=$tokens[$j]; if(is_string($tt) && $tt==="(") break; if(is_array($tt) && $tt[0]===T_STRING){ $name=$tt[1]; break; }
        }
        $pendingFunction=["name"=>$name,"class"=>end($classStack)?:null];
      }
      if($id===T_STRING && strcasecmp($text,"convertToArray")===0){
        $prevSig=null; for($j=$i-1;$j>=0;$j--){ $tt=$tokens[$j]; if(is_array($tt) && in_array($tt[0],[T_WHITESPACE,T_COMMENT,T_DOC_COMMENT],true)) continue; $prevSig=$tt; break; }
        if(is_array($prevSig) && $prevSig[0]===T_FUNCTION) continue;
        $nextSig=null; for($j=$i+1;$j<$n;$j++){ $tt=$tokens[$j]; if(is_array($tt) && in_array($tt[0],[T_WHITESPACE,T_COMMENT,T_DOC_COMMENT],true)) continue; $nextSig=$tt; break; }
        if($nextSig!=="(") continue;
        $fn=null; for($k=count($scopeStack)-1;$k>=0;$k--){ if($scopeStack[$k]["type"]==="function"){ $fn=$scopeStack[$k]; break; } }
        $caller=$fn ? (($fn["class"]? $fn["class"]."::":"").$fn["name"]) : "<global>";
        $uniq[$file."::".$caller]=["file"=>$file,"caller"=>$caller];
      }
    } else {
      if($t==="{"){
        $brace++;
        if($pendingClass!==null){ $classStack[]=$pendingClass; $scopeStack[]=["type"=>"class","name"=>$pendingClass,"brace"=>$brace]; $pendingClass=null; }
        if($pendingFunction!==null){ $pendingFunction["type"]="function"; $pendingFunction["brace"]=$brace; $scopeStack[]=$pendingFunction; $pendingFunction=null; }
      } elseif($t==="}"){
        while($scopeStack && end($scopeStack)["brace"]===$brace){ $s=array_pop($scopeStack); if($s["type"]==="class") array_pop($classStack); }
        $brace--;
      }
    }
  }
}
