import re
from collections import defaultdict
lines = open('/tmp/convert_refs.txt','r', encoding='utf-8').read().splitlines()
file_calls = defaultdict(list)
for line in lines:
    if not line:
        continue
    path, rest = line.split(':',1)
    ln = int(rest.split(':',1)[0])
    file_calls[path].append(ln)

file_contexts = {}
for path, lns in file_calls.items():
    try:
        content = open(path,'r', encoding='utf-8', errors='ignore').read().splitlines()
    except FileNotFoundError:
        continue
    contexts = []
    current_class = None
    current_func = None
    for line in content:
        stripped = line.strip()
        mclass = re.match(r'class\\s+(\\w+)', stripped)
        if mclass:
            current_class = mclass.group(1)
        mfunc = re.match(r'(public |protected |private )?(static )?function\\s+(\\w+)', stripped)
        if mfunc:
            current_func = mfunc.group(3)
        contexts.append((current_class, current_func))
    for ln in lns:
        if ln-1 < len(contexts):
            file_contexts.setdefault(path, set()).add(contexts[ln-1])
        else:
            file_contexts.setdefault(path, set()).add((None, None))

print('unique files', len(file_contexts))
print('sample files', list(file_contexts.items())[:5])
