    except FileNotFoundError:
        continue
    contexts = []
    current_class = None
    current_func = None
    for line in content:
        stripped = line.strip()
        mclass = re.match(r'class\\s+(\\w+)', stripped)
        if mclass:
            current_class = mclass.group(1)
        mfunc = re.match(r'(public |protected |private )?(static )?function\\s+(\\w+)', stripped)
        if mfunc:
            current_func = mfunc.group(3)
        contexts.append((current_class, current_func))
    for ln in lns:
        if ln-1 < len(contexts):
            file_contexts.setdefault(path, set()).add(contexts[ln-1])
        else:
            file_contexts.setdefault(path, set()).add((None, None))

print('unique files', len(file_contexts))
print('sample files', list(file_contexts.items())[:5])
